const tarefas = $input.all();

// pega a data solicitada diretamente do trigger do subworkflow
const dataSolicitada = $('When Executed by Another Workflow').first().json.data_solicitada;

// calcula o dia seguinte sem usar o campo due das tarefas
const [ano, mes, dia] = dataSolicitada.split('-').map(Number);
const dataBase = new Date(Date.UTC(ano, mes - 1, dia));
const proximoDia = new Date(dataBase);
proximoDia.setUTCDate(proximoDia.getUTCDate() + 1);

const dataSeguinte = proximoDia.toISOString().slice(0, 10);

// converte YYYY-MM-DD -> DD/MM/YYYY
function isoParaBr(iso) {
  const [y, m, d] = iso.split('-');
  return `${d}/${m}/${y}`;
}

// normaliza tarefas sem converter fuso do Google Tasks
const tarefasAbertas = tarefas
  .map(item => item.json)
  .filter(t => (t.status || '').toLowerCase() !== 'completed')
  .map(t => {
    const dueRaw = t.due || '';
    const dueDate = dueRaw ? String(dueRaw).slice(0, 10) : '';

    return {
      id: t.id || '',
      titulo: t.title || '',
      notes: t.notes || '',
      status: t.status || '',
      due: dueRaw,
      dueDate,
    };
  });

const tarefasDoDia = tarefasAbertas
  .filter(t => t.dueDate === dataSolicitada)
  .map(t => ({
    id: t.id,
    titulo: t.titulo,
  }));

const tarefasParaAdiantar = tarefasAbertas
  .filter(t => t.dueDate === dataSeguinte)
  .map(t => ({
    id: t.id,
    titulo: t.titulo,
  }));

return [
  {
    json: {
      data_solicitada_iso: dataSolicitada,
      data_solicitada_br: isoParaBr(dataSolicitada),
      data_seguinte_iso: dataSeguinte,
      data_seguinte_br: isoParaBr(dataSeguinte),
      tarefas_do_dia: tarefasDoDia,
      tarefas_para_adiantar: tarefasParaAdiantar,
      total_do_dia: tarefasDoDia.length,
      total_para_adiantar: tarefasParaAdiantar.length,
    }
  }
];
